// // Synchronous 3-bit binary counter with active-low reset functionality. On each falling edge of the clock signal, the counter decrements its value by one, unless the reset input is active, in which case it resets the count to seven.
module top_module(
  input clk,
  input reset,
  output reg [2:0] count
);always @(posedge clk) begin
  count <= (reset) ? 3'b0 : count + 1;
end

endmodule
